import { describe, expect, it } from 'vitest';

import {
  MESH_MODELS,
  meshOpenAiModelIds,
  resolveMeshModel,
  resolveMeshServingModel,
} from './mesh-model-registry';

const FOLDABLE_EDGEWORK_CHAT_MODELS = [
  'mistral-7b',
  'qwen3-8b',
  'qwen3-4b',
  'qwen2.5-7b',
  'qwen2.5-0.5b',
  'deepseek-r1-1.5b',
  'llama-3.2-3b',
  'tinyllama-1.1b',
  'gemma3-4b-it',
  'gemma4-12b-it',
  'codestral-22b',
];

describe('mesh model registry', () => {
  it('contains the foldable edgework-app chat models', () => {
    const ids = new Set(MESH_MODELS.map((model) => model.id));

    for (const model of FOLDABLE_EDGEWORK_CHAT_MODELS) {
      expect(ids.has(model), model).toBe(true);
      expect(resolveMeshModel(model)?.id).toBe(model);
    }
  });

  it('resolves gateway aliases to their mesh entries', () => {
    expect(resolveMeshModel('qwen2.5-0.5b-instruct')?.id).toBe('qwen2.5-0.5b');
    expect(resolveMeshModel('deepseek-r1-distill-qwen-1.5b')?.id).toBe(
      'deepseek-r1-1.5b',
    );
    expect(resolveMeshModel('llama-3.2-3b-instruct-q4km')?.id).toBe(
      'llama-3.2-3b',
    );
    expect(resolveMeshModel('google/gemma-4-12b-it')?.id).toBe('gemma4-12b-it');
    expect(resolveMeshModel('gemma-4-12b-it')?.id).toBe('gemma4-12b-it');
    expect(resolveMeshModel('codestral')?.id).toBe('codestral-22b');
    expect(resolveMeshModel('codestral-latest')?.id).toBe('codestral-22b');
    expect(resolveMeshModel('codestral-2405')?.id).toBe('codestral-22b');
  });

  it('advertises mesh ids and aliases through the OpenAI model catalog', () => {
    const ids = meshOpenAiModelIds();

    expect(ids).toContain('codestral-22b');
    expect(ids).toContain('codestral');
    expect(ids).toContain('codestral-latest');
    expect(ids).toContain('mistralai/codestral-22b-v0.1');
  });

  it('routes gemma (SentencePiece) models through the metaspace family, not GPT-2 BPE', () => {
    // REGRESSION 2026-06-22: gemma uses a SentencePiece `▁`-metaspace vocab. The
    // 'qwen2' family is GPT-2 byte-BPE — it byte-encodes spaces to `Ġ` (token
    // 245237) and never finds the `▁`-prefixed merges → high-vocab garbage. The
    // gemma4 entries MUST use 'hf-bpe-metaspace' + a tokenizer.json (like gemma3),
    // NOT a 'qwen2' GGUF sidecar.
    for (const id of ['gemma3-4b-it', 'gemma4-12b-it', 'gemma4-31b-it']) {
      const cfg = resolveMeshModel(id);
      expect(cfg, id).toBeDefined();
      expect(cfg?.tokenizerFamily, id).toBe('hf-bpe-metaspace');
      expect(cfg?.tokenizerJsonUrl, id).toMatch(/tokenizer\.json$/);
      expect(cfg?.tokenizerGgufUrl, id).toBeUndefined();
    }
  });

  it('pins stream-mode layer spans for models with non-default layer counts', () => {
    expect(resolveMeshModel('qwen3-8b')?.env?.FAT_STATION_LAYERS).toBe('0..36');
    expect(resolveMeshModel('qwen3-4b')?.env?.FAT_STATION_LAYERS).toBe('0..36');
    expect(resolveMeshModel('qwen2.5-0.5b')?.env?.FAT_STATION_LAYERS).toBe(
      '0..24',
    );
    expect(resolveMeshModel('tinyllama-1.1b')?.env?.FAT_STATION_LAYERS).toBe(
      '0..22',
    );
    expect(resolveMeshModel('gemma3-4b-it')?.env?.FAT_STATION_LAYERS).toBe(
      '0..34',
    );
    expect(resolveMeshModel('codestral-22b')?.env?.FAT_STATION_LAYERS).toBe(
      '0..56',
    );
  });

  it('routes dense Codestral through the Codestral tokenizer and not the 7B Mamba model', () => {
    const cfg = resolveMeshModel('codestral');
    expect(cfg?.id).toBe('codestral-22b');
    expect(cfg?.modelName).toBe('codestral-22b');
    expect(cfg?.knotUrl).toMatch(/codestral-22b-q4km\.knot$/);
    expect(cfg?.tokenizerFamily).toBe('hf-bpe-metaspace');
    expect(cfg?.chatTemplate).toBe('mistral-v3-instruct');
    expect(cfg?.tokenizerJsonUrl).toMatch(/mamba-codestral-tokenizer\.json$/);
    expect(cfg?.env?.KNOT_HTTP_TENSOR_CACHE_CAPACITY).toBe('64');
    expect(cfg?.env?.MOONSHINE_KNOT_BACKGROUND_LOCALIZE).toBe('0');
    expect(cfg?.env?.MOONSHINE_SOVEREIGN_SIEVE).toBe('0');
    expect(cfg?.env?.MOONSHINE_DISABLE_NATIVE_GENERATE).toBeUndefined();
    expect(cfg?.env?.MESH_GPU_Q4K_BUDGET_GB).toBe('12');
    expect(cfg?.fluxGpuF16BudgetGb).toBe(4);
  });

  it('keeps dense Codestral exact unless the explicit fastlane is enabled', () => {
    expect(resolveMeshServingModel('codestral-22b').config?.id).toBe('codestral-22b');

    const routed = resolveMeshServingModel('codestral-22b', { codestralFastLane: true });
    expect(routed.requestedConfig?.id).toBe('codestral-22b');
    expect(routed.config?.id).toBe('mamba-codestral-7b');
    expect(routed.rewriteModel).toBe('mamba-codestral-7b');
    expect(routed.routedFrom).toBe('codestral-22b');
    expect(routed.reason).toBe('codestral-fastlane');

    const aliasRouted = resolveMeshServingModel('codestral', { codestralFastLane: true });
    expect(aliasRouted.config?.id).toBe('mamba-codestral-7b');
    expect(aliasRouted.rewriteModel).toBe('mamba-codestral-7b');
  });

  it('lets Mamba-Codestral prefer a baked local knot when present', () => {
    const cfg = resolveMeshModel('mamba-codestral-7b');
    expect(cfg?.chatTemplate).toBe('raw');
    expect(cfg?.env?.MESH_GPU_Q8K).toBe('1');
    expect(cfg?.env?.MESH_GPU_Q8K_F32).toBe('1');
    expect(cfg?.env?.MESH_GPU_Q8K_BUDGET_GB).toBe('12');
    expect(cfg?.env?.MESH_GPU_SSM_FUSED).toBe('1');
    expect(cfg?.env?.MOONSHINE_KNOT_LOAD_MODE).toBe('race');
  });
});
